class MatchRequest(BaseModel):
    transcript: str

class EntryCreate(BaseModel):
    item_code: str
    job: str
    supplier: str
    description: str
    cost_quantity: float
    unit: str
    gl_code: Optional[str] = None
    comments: Optional[str] = None

@app.get("/api/products")
async def get_products():
    return PRODUCTS

@app.get("/api/jobs")
async def get_jobs():
    return JOBS

@app.post("/api/match")
async def match_product(req: MatchRequest):
    client = OpenAI(api_key=os.environ["OPENAI_API_KEY"])
    products_json = json.dumps(PRODUCTS)
    jobs_json = json.dumps(JOBS)
    response = client.chat.completions.create(
        model="gpt-4o",
        max_tokens=1500,
        response_format={"type": "json_object"},
        messages=[
            {"role": "system", "content": "You are a stock management assistant for a NZ construction company. Always respond with valid JSON only."},
            {"role": "user", "content": f"""A worker said: "{req.transcript}"

PRODUCTS (match by description, code, or alias):
{products_json}

JOBS (match job number or name):
{jobs_json}

Extract:
1. Product - use alias field for nicknames/misspellings
2. Job - match closest from job list by number or name
3. Quantity - a number
4. Person name (comments)

Return JSON:
{{
  "matches": [{{"code":"...","description":"...","supplier":"...","unit":"...","gl":"..."}}],
  "job": "exact match from job list or null",
  "job_suggestions": ["up to 3 close matches if ambiguous"],
  "quantity": null,
  "comments": "...",
  "ambiguous": false,
  "missing": []
}}

Put null and add to missing[] for anything not in transcript.
"""}
        ]
    )
    return json.loads(response.choices[0].message.content.strip())

@app.post("/api/entries")
async def create_entry(entry: EntryCreate):
    import datetime
    conn = await get_db()
    try:
        nz_today = datetime.datetime.now(NZ_TZ).date()
        row = await conn.fetchrow("""
            INSERT INTO stock_entries (item_code, entry_date, job, supplier, description, cost_quantity, unit, gl_code, comments)
            VALUES ($1,$2,$3,$4,$5,$6,$7,$8,$9) RETURNING *
        """, entry.item_code, nz_today, entry.job, entry.supplier,
            entry.description, entry.cost_quantity, entry.unit, entry.gl_code, entry.comments)
        return dict(row)
    finally:
        await conn.close()

@app.get("/api/entries")
async def list_entries():
    conn = await get_db()
    try:
        rows = await conn.fetch("SELECT * FROM stock_entries ORDER BY created_at DESC")
        return [dict(r) for r in rows]
    finally:
        await conn.close()

@app.get("/api/export")
async def export_csv():
    conn = await get_db()
    try:
        rows = await conn.fetch("SELECT item_code, entry_date, job, cost_quantity, gl_code, comments FROM stock_entries ORDER BY created_at ASC")
    finally:
        await conn.close()
    output = io.StringIO()
    writer = csv.writer(output)
    writer.writerow(["Item Code","Date","Job Number","Subcategory","Cost Quantity","GL Code","Comments"])
    for r in rows:
        writer.writerow([r["item_code"], r["entry_date"], r["job"], "", r["cost_quantity"], "", r["comments"] or ""])
    output.seek(0)
    return StreamingResponse(iter([output.getvalue()]), media_type="text/csv",
        headers={"Content-Disposition": f"attachment; filename=stock_export_{date.today()}.csv"})

@app.delete("/api/entries/{entry_id}")
async def delete_entry(entry_id: int):
    conn = await get_db()
    try:
        await conn.execute("DELETE FROM stock_entries WHERE id = $1", entry_id)
        return {"ok": True}
    finally:
        await conn.close()

app.mount("/", StaticFiles(directory="frontend/dist", html=True), name="static")
